#include<bits/stdc++.h>
using namespace std;
int n,k,t;
string s,str;
bool check(int x,int k) {
	str='0'+s;
	int i=1,ans=0;
	while(i<=n) {
		if(str[i]=='1') {
			i+=x;
			ans++;
		} else {
			i++;
		}
	}
	return ans<=k;
}
int main() {
	cin>>t;
	while(t--) {
		cin>>n>>k;
		cin>>s;
		int l=1,r=n;
		while(l<r) {
			int mid=(l+r)>>1;
			if(check(mid,k)) {
				r=mid;
			} else {
				l=mid+1;
			}
		}
		cout<<r<<"\n";
	}
	return 0;
}
